import com.atlassian.jira.component.ComponentAccessor
import com.atlassian.jira.event.type.EventDispatchOption

def customFieldManager = ComponentAccessor.getCustomFieldManager()
def userManager = ComponentAccessor.getUserManager()
def mailServer = ComponentAccessor.getMailServerManager().getDefaultSMTPMailServer()

def issue = event.issue
def cf = customFieldManager.getCustomFieldObjectByName('Deploy Approver')
def approver = issue.getCustomFieldValue(cf)

if (approver) {
    mailServer.send(approver.emailAddress, 'Deployment approved', "Issue ${issue.key} is ready for production.")
}

issue.setCustomFieldValue(cf, null)
ComponentAccessor.getIssueManager().updateIssue(userManager.getUserByName('admin'), issue, EventDispatchOption.DO_NOT_DISPATCH, false)

import groovy.sql.Sql
import java.nio.file.Files
import java.nio.file.Paths

def sql = Sql.newInstance('jdbc:postgresql://internal-db:5432/jira', 'jira_user', 'secret', 'org.postgresql.Driver')
def rows = sql.rows('SELECT assignee_id, count(*) as total FROM issues WHERE project = ? GROUP BY assignee_id', ['HR'])

rows.each { row ->
    def reportPath = Paths.get("/var/reports/hr_${row.assignee_id}.txt")
    Files.write(reportPath, "Assignee ${row.assignee_id} has ${row.total} issues".bytes)
}
sql.close()
